public boolean equals(Object o) {
    if (this == o) return true;
    if (o == null || getClass() != o.getClass()) return false;
    if (!super.equals(o)) return false;

    Element element = (Element) o;

    return text().equals(element.text()) &&
           className().equals(element.className()) &&
           attributes().equals(element.attributes()) &&
           childElementsEqual(element);
}

private boolean childElementsEqual(Element other) {
    if (children().size() != other.children().size()) return false;
    for (int i = 0; i < children().size(); i++) {
        if (!children().get(i).equals(other.children().get(i))) {
            return false;
        }
    }
    return true;
}

public boolean equals(Object o) {
    if (this == o) return true;
    if (o == null || getClass() != o.getClass()) return false;
    if (!super.equals(o)) return false;

    Element element = (Element) o;

    // Compare the attributes and HTML content of the two elements
    return attributes.equals(element.attributes) && text().equals(element.text()) && children().equals(element.children());
}

